import React from "react";

export default function Register() {
  return (
    <div style={{ padding: "40px", textAlign: "center" }}>
      <h1>Sign in</h1>
      <p>შედეგების შესანახად გაიარე ავტორიზაცია</p>
      <button
        style={{
          padding: "12px 30px",
          fontSize: "18px",
          borderRadius: "8px",
          cursor: "pointer"
        }}
      >
        Sign in with Google
      </button>
    </div>
  );
}
